function doEndPracticeSession() {
  endPracticeSession();
  // Reset timer pour nouvelle session
  _fpStopTimer();
  _fpTimerStart = null;
  _fpTimerElapsed = 0;
  _fpTimerPaused = false;
  if (RACE_STATE.practice) RACE_STATE.practice._timerSessionIdx = -1;
  renderPracticeSection();
  if (typeof renderAdvancedSetupUI === "function") renderAdvancedSetupUI();
}

function backToSetupForPractice() {
  rtab("prep", true);
  refreshPrepButtonForPractice();
}

function refreshPrepButtonForPractice() {
  var e = document.getElementById("prep-go-next-btn");
  if (e) {
    if (!hasPracticeSystem()) { e.textContent = "Continuer →"; e.setAttribute("onclick", "goToNextRaceStep()"); return; }
    var t = RACE_STATE.practice;
    if (!t || 0 === t.tests.length) { e.textContent = "Continuer →"; e.setAttribute("onclick", "goToNextRaceStep()"); return; }
    var allDone = t.sessionsCompleted >= getPracticeMaxSessions();
    if (allDone) { e.textContent = "Aller en qualif →"; e.setAttribute("onclick", "goToQualifStep()"); }
    else { e.textContent = "Essais libres ▶"; e.setAttribute("onclick", "goToEssaisAndRun()"); }
  }
}

function goToEssaisAndRun() {
  rtab("essais", true);
}
